private String toString(Object value) {
	Class<?> type = value.getClass();
	if (type.isArray()) {
		StringBuilder builder = new StringBuilder("{");
		int arrayLength = Array.getLength(value);
		for (int i = 0; i < arrayLength; i++) {
			if (i > 0) {
				builder.append(", ");
			}
			builder.append(toString(Array.get(value, i)));
		}
		builder.append('}');
		return builder.toString();
	}
	if (type == String.class) {
		return '"' + ((String) value) + '"';
	}
	if (type == Character.class) {
		return '\'' + value.toString() + '\'';
	}
	if (type == Byte.class) {
		return String.format("(byte)0x%02x", value);
	}
	if (type == Long.class) {
		return Long.toString((Long) value) + 'L';
	}
	if (type == Float.class) {
		return Float.toString((Float) value) + 'f';
	}
	if (type == Double.class) {
		return Double.toString((Double) value);
	}
	if (value instanceof Enum<?> e) {
		return e.name();
	}
	if (type == Class.class) {
		return ClassUtils.getCanonicalName((Class<?>) value) + ".class";
	}
	return String.valueOf(value);
}

private URI getUriToUse() {
	if (this.uriPath == null) {
		return this.uri;
	}

	StringBuilder uriBuilder = new StringBuilder();
	if (this.uri.getScheme() != null) {
		uriBuilder.append(this.uri.getScheme()).append(':');
	}
	if (this.uri.getRawUserInfo() != null || this.uri.getHost() != null) {
		uriBuilder.append("//");
		if (this.uri.getRawUserInfo() != null) {
			uriBuilder.append(this.uri.getRawUserInfo()).append('@');
		}
		if (this.uri.getHost() != null) {
			uriBuilder.append(this.uri.getHost());
		}
		if (this.uri.getPort() != -1) {
			uriBuilder.append(':').append(this.uri.getPort());
		}
	}
	if (StringUtils.hasLength(this.uriPath)) {
		uriBuilder.append(this.uriPath);
	}
	if (this.uri.getRawQuery() != null) {
		uriBuilder.append('?').append(this.uri.getRawQuery());
	}
	if (this.uri.getRawFragment() != null) {
		uriBuilder.append('#').append(this.uri.getRawFragment());
	}
	try {
		return new URI(uriBuilder.toString());
	}
	catch (URISyntaxException ex) {
		throw new IllegalStateException("Invalid URI path: \"" + this.uriPath + "\"", ex);
	}
}

static OAuth2AuthorizationResponse convert(MultiValueMap<String, String> request, String redirectUri) {
	String code = request.getFirst(OAuth2ParameterNames.CODE);
	String errorCode = request.getFirst(OAuth2ParameterNames.ERROR);
	String state = request.getFirst(OAuth2ParameterNames.STATE);
	if (StringUtils.hasText(code)) {
		OAuth2AuthorizationResponse.Builder builder = OAuth2AuthorizationResponse.success(code)
			.redirectUri(redirectUri);
		if (state != null) {
			builder.state(state);
		}
		return builder.build();
	}
	if (!StringUtils.hasText(errorCode)) {
		errorCode = "unknown_error";
	}
	String errorDescription = request.getFirst(OAuth2ParameterNames.ERROR_DESCRIPTION);
	String errorUri = request.getFirst(OAuth2ParameterNames.ERROR_URI);
	OAuth2AuthorizationResponse.Builder builder = OAuth2AuthorizationResponse.error(errorCode)
		.redirectUri(redirectUri);
	if (errorDescription != null) {
		builder.errorDescription(errorDescription);
	}
	if (errorUri != null) {
		builder.errorUri(errorUri);
	}
	if (state != null) {
		builder.state(state);
	}
	return builder.build();
}
